module mg_05412 (y, x);
input [4:0] x; 
  output [4:0] y; 
  reg [4:0] y; 
  always @ (x) 
  begin 
  y[0] = x[4]; 
  y[1] = x[0]; 
  y[2] = x[1] ^ x[4]; 
