  parameter modrm_st = 3'h1; 
  parameter offse_st = 3'h2; 
  parameter immed_st = 3'h3; 
  parameter execu_st = 3'h4; 
  wire into, end_instr, end_into; 
  wire [2:0] n_state; 
  wire intr_ifl; 
  assign into = (ftype==6'b111_010); 
  assign end_into = into ? ~of : end_seq; 
  assign end_instr = !div_exc && !intr_ifl && end_into && !next_in_exec; 
  assign intr_ifl = intr & ifl; 
 assign n_state = (state == opcod_st) ? (prefix ? opcod_st: (next_in_opco ? opcod_st: (need_modrm ? modrm_st: (need_off ? offse_st: (need_imm ? immed_st : execu_st))))) 
 : (state == modrm_st) ? (need_off ? offse_st: (need_imm ? immed_st : execu_st)) 
  : (state == offse_st) ? (need_imm ? immed_st : execu_st) 
  : (state == immed_st) ? (execu_st) 
  : (end_instr ? opcod_st : execu_st); 
  assign next_state = block ? state : n_state; 
 endmodule

