  output [15:0] data_o; 
  output valid_o, done_o; 
  reg [15:0] data_o; 
  reg done_o; 
  reg valid_o; 
  reg cnt; 
  always @(posedge clk or posedge rst) 
  begin 
  if (rst) 
  cnt <= #1 1'b0; 
  else if (out_valid) 
  cnt <= #1 cnt + 1'b1; 
  end 
  always @(posedge clk) 
  begin 
  if (~cnt && out_valid) 
  data_o[7:0] <= #1 out_data; 
