  always @(posedge clk) 
  begin 
  if (cnt && out_valid) 
  data_o[15:8] <= #1 out_data; 
  end 
  always @(posedge clk) 
  begin 
  if ((&cnt) && out_valid) 
  valid_o <= #1 1'b1; 
  else 
  valid_o <= #1 1'b0; 
  end 
  always @(posedge clk) 
  done_o <= #1 out_done; 
 endmodule

