  localparam IDLE = 2'd0; 
  localparam TX_OPERAND01 = 2'd1; 
  localparam TX_OPERAND02 = 2'd2; 
  localparam TX_ALU_CTRL = 2'd3; 
  assign stateID = state; 
  always@(*) begin 
  next_state = state; 
  send16 = 1'b1; 
  case (state) 
  IDLE: begin 
  if(PB & ~busy) begin 
  next_state=TX_OPERAND01; 
  end 
  end 
  TX_OPERAND01: begin 
  if(PB & ~busy) begin 
  next_state=TX_OPERAND02; 
  end 
  end 
  TX_OPERAND02: begin 
  if(PB & ~busy) begin 
  next_state=TX_ALU_CTRL; 
  end 
  end 
  TX_ALU_CTRL: begin 
  send16 = 1'b0; 
  if(~busy) begin 
  next_state=IDLE; 
  end 
  end 
  endcase 
  end 
  always@(posedge clock) begin 
  if(reset) 
  state <= IDLE; 
  else 
  state <= next_state; 
  end 
