module rtlpp_08116(clk, nrst, tx_data, tx_start, tx_busy, txd);

parameter CLK_HZ = 200_000_000;
parameter BAUD = 9600;
parameter BAUD_DIVISOR = CLK_HZ / BAUD;

input wire clk;
input wire nrst;

input wire [7:0] tx_data;
input wire tx_start;		
output reg tx_busy;
output reg txd;

reg [9:0] tx_shifter;
reg [15:0] tx_sample_cntr;

initial begin
	tx_busy = 0;
	txd = 1;
	tx_shifter = 0;
        tx_sample_cntr = 0;
end

always @ (posedge clk) begin
	if ((~nrst) || (tx_sample_cntr == 0)) begin
		tx_sample_cntr <= (BAUD_DIVISOR-1);
	end else begin
		tx_sample_cntr <= tx_sample_cntr - 1;
	end
end

wire tx_do_sample = (tx_sample_cntr == 0);

always @ (posedge clk) begin
	if (~nrst) begin
		tx_busy <= 0;
		tx_shifter <= 0;
		txd <= 1;
	end else begin
		if (~tx_busy) begin
			if (tx_start) begin		
				tx_shifter <= {1'b1,tx_data,1'b0};
				tx_busy <= 1;
			end
		end else begin
			if (tx_do_sample) begin		
				{tx_shifter,txd} <= {tx_shifter,txd} >> 1;	
				if (~|tx_shifter[9:1]) begin		
					tx_busy <= 0;					
				end
			end	
		end	
	end 
end

endmodule

