module autovcoder_065809 (
    Q,
    RESET_B,
    D,
    GATE_N,
    VPWR,
    VGND,
    VPB,
    VNB
);

  // Module ports
  output Q;
  input RESET_B;
  input D;
  input GATE_N;
  input VPWR;
  input VGND;
  input VPB;
  input VNB;

  // Local signals
  wire RESET;
  wire intgate;
  reg  notifier;
  wire D_delayed;
  wire GATE_N_delayed;
  wire RESET_delayed;
  wire RESET_B_delayed;
  wire buf_Q;
  wire awake;
  wire cond0;
  wire cond1;

  //                                     Name     Output   Other arguments
  not not0 (RESET, RESET_B_delayed);
  not not1 (intgate, GATE_N_delayed);
  sky130_fd_sc_hd__udp_dlatch$PR_pp$PG$N dlatch0 (
      buf_Q,
      D_delayed,
      intgate,
      RESET,
      notifier,
      VPWR,
      VGND
  );
  assign awake = (VPWR === 1'b1);
  assign cond0 = (awake && (RESET_B_delayed === 1'b1));
  assign cond1 = (awake && (RESET_B === 1'b1));
  buf buf0 (Q, buf_Q);

endmodule

