module origen_197312(
    input memWrite,
    input memRead,
    input [31:0] virtualAddress,
    output reg [12:0] physicalAddress,
    output reg [2:0] memEn,
    output reg [1:0] memBank,
    output reg invalidAddress
);

always @(*) begin
    if (memWrite | memRead) begin
        // Region 1: 0x10010000 to 0x10010FFF (4 KB)
        if (virtualAddress >= 32'h10010000 && virtualAddress <= 32'h10010FFF) begin
            physicalAddress = virtualAddress[12:0];
            memEn = 3'b001;
            memBank = 2'b00;
            invalidAddress = 1'b0;
        // Region 2: 0x7FFFEFFC to 0x7FFFFFFB (4 KB)
        end else if (virtualAddress >= 32'h7FFFEFFC && virtualAddress <= 32'h7FFFFFFB) begin
            physicalAddress = virtualAddress[12:0];
            memEn = 3'b010;
            memBank = 2'b01;
            invalidAddress = 1'b0;
        // Region 3: 0xB800 to 0xCACF (16 KB)
        end else if (virtualAddress >= 32'hB800 && virtualAddress <= 32'hCACF) begin
            physicalAddress = virtualAddress[13:1];
            memEn = 3'b100;
            memBank = 2'b10;
            invalidAddress = 1'b0;
        // Region 4: 0xFFFF0000 to 0xFFFF000C (12 B)
        end else if (virtualAddress >= 32'hFFFF0000 && virtualAddress <= 32'hFFFF000C) begin
            physicalAddress = virtualAddress[3:0];
            memEn = 3'b001;
            memBank = 2'b00;
            invalidAddress = 1'b0;
        end else begin
            physicalAddress = 13'bz;
            memEn = 3'bz;
            memBank = 2'bz;
            invalidAddress = 1'b1;
        end
    end else begin
        physicalAddress = 13'bz;
        memEn = 3'bz;
        memBank = 2'bz;
        invalidAddress = 1'b0;
    end
end

endmodule

