    //checking timing for control signals


    //checking the pulse width

    $width(posedge OCLK, 0, 0, NOTIFY_REG);
    $width(negedge OCLK, 0, 0, NOTIFY_REG);

    //checing the recovery data


  endspecify

endmodule

