            exp_10_o <= 0;
        else
            exp_10_o <= s_exp_10_o;

    assign s_opa_dn = !(|s_expa);
    assign s_opb_dn = !(|s_expb);

    assign fracta_24_o = {!s_opa_dn, s_fracta};
    assign fractb_24_o = {!s_opb_dn, s_fractb};

    assign s_expa_in = {2'd0, s_expa} + {9'd0, s_opa_dn};
