  pcie_rstn = 1'b1; 
  rp_rstn = 1'b0; 
  ref_clk_out = 1'b0; 
  #1000 
  pcie_rstn = 1'b0; 
  rp_rstn = 1'b1; 
  #1000 
  rp_rstn = 1'b0; 
  #1000 
  rp_rstn = 1'b1; 
  #1000 
  rp_rstn = 1'b0; 
  #200000 pcie_rstn = 1'b1; 
  #100000 rp_rstn = 1'b1; 
