module rtlpp_01815 (clk, x_in0, x_in1, x_in2, y); 

  input         clk;
  input  [3:0]  x_in0, x_in1, x_in2;
  output [6:0]  y;
  reg    [6:0]  y;
  reg    [3:0]  x0, x1, x2;
  wire   [2:0]  table_in;
  wire   [3:0]  table_out;

  reg [6:0] p;  

  assign table_in[0] = x0[0];
  assign table_in[1] = x1[0];
  assign table_in[2] = x2[0];

  always @(posedge clk)  
  begin : DA
    parameter s0=0, s1=1;
    integer k;
    reg [0:0] state = s0;
    reg [2:0] count;           
    case (state) 
      s0 : begin               
        state <= s1;
        count = 0;
        p  <= 0;           
        x0 <= x_in0;
        x1 <= x_in1;
        x2 <= x_in2;
      end
      s1 : begin               
        if (count == 4) begin  
          y <= p;              
          state <= s0;         
        end
        else begin    
          if (count == 3)   
            p <= {p[6],p[6:1]} - (table_out << 3);  
          else          
            p <= {p[6],p[6:1]} + (table_out << 3);
          for (k=0; k<=2; k= k+1) begin     
            x0[k] <= x0[k+1];
            x1[k] <= x1[k+1];
            x2[k] <= x2[k+1];
          end
          count = count + 1;
          state <= s1;
        end
      end
    endcase  
  end

  // Integrated logic of case3s module here
  assign table_out = (table_in == 3'b000) ? 4'b0001 :
                     (table_in == 3'b001) ? 4'b0010 :
                     (table_in == 3'b010) ? 4'b0011 :
                     (table_in == 3'b011) ? 4'b0100 :
                     (table_in == 3'b100) ? 4'b0101 :
                     (table_in == 3'b101) ? 4'b0110 :
                     (table_in == 3'b110) ? 4'b0111 :
                     4'b1000;

endmodule

