 reg [SIZE-1:0] state ; 
 reg [SIZE-1:0] next_state ; 
 always @ (state or req_0 or req_1) 
 begin : FSM_COMBO 
  next_state = 3'b000; 
  case(state) 
  IDLE : if (req_0 == 1'b1) begin 
  next_state = GNT0; 
  end else if (req_1 == 1'b1) begin 
  next_state= GNT1; 
  end else begin 
  next_state = IDLE; 
  end 
  GNT0 : if (req_0 == 1'b1) begin 
  next_state = GNT0; 
  end else begin 
  next_state = IDLE; 
  end 
  GNT1 : if (req_1 == 1'b1) begin 
  next_state = GNT1; 
  end else begin 
  next_state = IDLE; 
  end 
  default : next_state = IDLE; 
  endcase 
 end 
 always @ (posedge clock) 
 begin : FSM_SEQ 
  if (reset == 1'b1) begin 
  state <= IDLE; 
  end else begin 
  state <= next_state; 
  end 
 end 
 always @ (state) 
 begin : OUTPUT_LOGIC 
  case(state) 
  IDLE : begin 
  gnt_0 = 1'b0; 
  gnt_1 = 1'b0; 
  end 
  GNT0 : begin 
  gnt_0 = 1'b1; 
  gnt_1 = 1'b0; 
  end 
  GNT1 : begin 
  gnt_0 = 1'b0; 
  gnt_1 = 1'b1; 
  end 
  default : begin 
  gnt_0 = 1'b0; 
  gnt_1 = 1'b0; 
  end 
  endcase 
 end 
 endmodule

