 initial begin 
  state <= IDLE; 
  din <= 16'h0000; 
  daddr <= 7'h00; 
  den <= 1'b0; 
  dwe <= 1'b0; 
  valid <= 1'b0; 
  data_out <= 16'h0000; 
 end 
 always@(posedge clk or posedge rst) begin 
  if(rst) 
  state <= IDLE; 
  else begin 
  case(state) 
  IDLE: begin 
  din <= 16'h0000; 
  daddr <= 7'h00; 
  den <= 1'b0; 
  dwe <= 1'b0; 
  valid <= 1'b0; 
  data_out <= 16'h0000; 
  if(!busy) begin 
  if(eoc || eos) begin 
  if(rd && !wr) begin 
  den <= 1'b1; 
  dwe <= 1'b0; 
  daddr <= 7'h03; 
  state <= READ; 
  end 
  else if(wr && !rd) begin 
  den <= 1'b1; 
  dwe <= 1'b1; 
  din <= data_in; 
  daddr <= addr; 
  state <= WRITE; 
  end 
  end 
  end 
  end 
  WRITE: begin 
  den <= 1'b0; 
  dwe <= 1'b0; 
  if(drdy) begin 
  valid <= 1'b1; 
  state <= IDLE; 
  end 
  end 
  READ: begin 
  den <= 1'b0; 
  dwe <= 1'b0; 
  if(drdy) begin 
  data_out <= dout; 
  valid <= 1'b1; 
  state <= IDLE; 
  end 
  end 
  endcase 
  end 
 end 
 endmodule

