    input  wire [30:0] iIn11,
    input  wire [30:0] iIn12,
    input  wire [30:0] iIn13,
    input  wire [30:0] iIn14,
    output wire [ 3:0] oMinimum
);

  reg [ 3:0] index0_0;
  reg [ 3:0] index0_1;
  reg [ 3:0] index0_2;
  reg [ 3:0] index0_3;
  reg [ 3:0] index0_4;
  reg [ 3:0] index0_5;
  reg [ 3:0] index0_6;
  reg [ 3:0] rindex0_7;
  reg [ 3:0] index1_0;
  reg [ 3:0] index1_1;
  reg [ 3:0] index1_2;
  reg [ 3:0] index1_3;
  reg [ 3:0] index2_0;
  reg [ 3:0] index2_1;
