 begin 
  if (reset) 
  begin 
  stream_out_data <= 'h0; 
  stream_out_startofpacket <= 1'b0; 
  stream_out_endofpacket <= 1'b0; 
  stream_out_empty <= 'h0; 
  stream_out_valid <= 1'b0; 
