module mg_06900(input_a,input_a_stb,output_z_ack,clk,rst,output_z,output_z_stb,input_a_ack);
input clk; 
  input rst; 
  input [63:0] input_a; 
  input input_a_stb; 
  output input_a_ack; 
  output [63:0] output_z; 
  output output_z_stb; 
  input output_z_ack; 
  reg s_output_z_stb; 
  reg [63:0] s_output_z; 
  reg s_input_a_ack; 
  reg [2:0] state; 
  parameter get_a = 3'd0, 
  special_cases = 3'd1, 
  unpack = 3'd2, 
  convert = 3'd3, 
  put_z = 3'd4; 
  reg [63:0] a_m, a, z; 
  reg [11:0] a_e; 
  reg a_s; 
  always @(posedge clk) 
  begin 
  case(state) 
  get_a: 
  begin 
  s_input_a_ack <= 1; 
  if (s_input_a_ack && input_a_stb) begin 
  a <= input_a; 
  s_input_a_ack <= 0; 
  state <= unpack; 
  end 
  end 
  unpack: 
  begin 
  a_m[63:11] <= {1'b1, a[51 : 0]}; 
  a_m[10:0] <= 0; 
  a_e <= a[62 : 52] - 1023; 
  a_s <= a[63]; 
  state <= special_cases; 
  end 
  special_cases: 
  begin 
  if ($signed(a_e) == -1023) begin 
  z <= 0; 
  state <= put_z; 
  end else if ($signed(a_e) == 1024 && a[51:0] != 0) begin 
  z <= 64'h8000000000000000; 
  state <= put_z; 
  end else if ($signed(a_e) > 63) begin 
  if (a_s) begin 
  z <= 64'h8000000000000000; 
  end else begin 
  z <= 64'h0000000000000000; 
  end 
  state <= put_z; 
  end else begin 
  state <= convert; 
  end 
  end 
  convert: 
  begin 
  if ($signed(a_e) < 63 && a_m) begin 
  a_e <= a_e + 1; 
  a_m <= a_m >> 1; 
  end else begin 
  if (a_m[63] && a_s) begin 
  z <= 64'h8000000000000000; 
  end else begin 
  z <= a_s ? -a_m : a_m; 
  end 
  state <= put_z; 
  end 
  end 
  put_z: 
  begin 
  s_output_z_stb <= 1; 
  s_output_z <= z; 
  if (s_output_z_stb && output_z_ack) begin 
  s_output_z_stb <= 0; 
  state <= get_a; 
  end 
  end 
  endcase 
  if (rst == 1) begin 
  state <= get_a; 
  s_input_a_ack <= 0; 
  s_output_z_stb <= 0; 
  end 
  end 
  assign input_a_ack = s_input_a_ack; 
  assign output_z_stb = s_output_z_stb; 
  assign output_z = s_output_z; 
 endmodule

