module autovcoder_093261 #(
    parameter data_width = 6,
    parameter address_width = 2
) (
    output reg clk,
    reset,
    wr_enable,
    output reg [data_width-1:0] data_in,
    output reg D0_pop,
    D1_pop,
    output reg init,
    output reg [3:0] umbral_MFs,
    output reg [3:0] umbral_VCs,
    output reg [3:0] umbral_Ds,
    input [5:0] data_out_D0,
    data_out_D1,
    data_out_D0_synth,
    data_out_D1_synth,
    input empty_fifo_D0,
    empty_fifo_D1,
    input error_D0,
    error_D1,
    error_D0_synth,
    error_D1_synth,
    input error_out,
    input active_out,
    input idle_out,
    input error_out_synth,
    input active_out_synth,
    input idle_out_synth,
    input empty_fifo_D0_synth,
    empty_fifo_D1_synth
);

  initial begin
    $dumpfile("prueba_full_umbrales.vcd");
    $dumpvars;

    {wr_enable, reset} <= 0;
    data_in <= 0;
    D0_pop <= 0;
    D1_pop <= 0;
    init <= 0;
    umbral_MFs[3:0] <= 1;
    umbral_VCs[3:0] <= 3;
    umbral_Ds[3:0] <= 2;

    @(posedge clk);
    @(posedge clk);
    @(posedge clk);
    @(posedge clk);
    wr_enable <= 1;
    reset <= 1;
    data_in <= 6'b001000;

    @(posedge clk);
    data_in <= 6'b010101;

    @(posedge clk);
    init <= 1;
    data_in <= 6'b000100;
    /////////////
    @(posedge clk);
    wr_enable <= 1;
    data_in   <= 6'b010110;

    @(posedge clk);
    data_in <= 6'b010100;
    umbral_MFs[3:0] <= 1111;
    umbral_VCs[3:0] <= 1101;
    umbral_Ds[3:0] <= 1110;

    @(posedge clk);
    init <= 0;
    reset <= 0;
    data_in <= 6'b000101;

    @(posedge clk);
    data_in <= 6'b010100;

    @(posedge clk);
    data_in <= 6'b000101;

    @(posedge clk);
    reset   <= 1;
    data_in <= 6'b110100;


    @(posedge clk);
    wr_enable <= 0;
    data_in   <= 6'b000101;

    @(posedge clk);
    data_in <= 6'b110100;

    @(posedge clk);
    init <= 1;
    data_in <= 6'b110100;

    @(posedge clk);
    D0_pop <= 1;
    D1_pop <= 1;

    @(posedge clk);

    repeat (10) begin
      @(posedge clk);
    end


    $finish;
  end
  initial clk <= 1;
  always #1 clk <= ~clk;
endmodule

