  );
  CS_MUXCO_PRIM MUXCO_5 (
      .AIN (CA[5]),
      .CIN (\MUXCO_4|COUT_net ),
      .COUT(\MUXCO_5|COUT_net ),
      .CSEL(DX[5])
  );
  CS_MUXCO_PRIM MUXCO_6 (
      .AIN (CA[6]),
      .CIN (\MUXCO_5|COUT_net ),
      .COUT(CO),
      .CSEL(DX[6])
  );
  CS_XORCI_PRIM XORCI_0 (
      .CIN(CI),
      .DIN(DX[0]),
      .SUM(SUM[0])
  );
  CS_XORCI_PRIM XORCI_1 (
      .CIN(\MUXCO_0|COUT_net ),
      .DIN(DX[1]),
      .SUM(SUM[1])
  );
  CS_XORCI_PRIM XORCI_2 (
      .CIN(\MUXCO_1|COUT_net ),
