module origen_148201(
    input [3:0] a,
    input [3:0] b,
    output [7:0] product
);

    wire [3:0] shifted_a;
    wire [3:0] partial_products [3:0];
    wire [7:0] sum_partial_products;

    // Barrel shifter
    barrel_shifter_4bit shifter (
        .data_in(a),
        .shift_amount(2'b00),  // No shift for multiplication
        .direction(1'b0),      // Left shift
        .data_out(shifted_a)
    );

    // Generate partial products
    genvar i;
    generate
        for (i = 0; i < 4; i = i + 1) begin : partial_product_gen
            assign partial_products[i] = b[i] ? (shifted_a << i) : 4'b0000;
        end
    endgenerate

    // Sum partial products
    assign sum_partial_products = partial_products[0] + 
                                  {partial_products[1], 1'b0} + 
                                  {partial_products[2], 2'b00} + 
                                  {partial_products[3], 3'b000};

    // Assign final product
    assign product = sum_partial_products;

endmodule

// Barrel shifter module
module barrel_shifter_4bit(
    input [3:0] data_in,
    input [1:0] shift_amount,
    input direction,
    output reg [3:0] data_out
);

    always @(*) begin
        case ({direction, shift_amount})
            3'b000: data_out = data_in;
            3'b001: data_out = {data_in[0], data_in[3:1]};
            3'b010: data_out = {data_in[1:0], data_in[3:2]};
            3'b011: data_out = {data_in[2:0], data_in[3]};
            3'b100: data_out = data_in;
            3'b101: data_out = {data_in[2:0], data_in[3]};
            3'b110: data_out = {data_in[1:0], data_in[3:2]};
            3'b111: data_out = {data_in[0], data_in[3:1]};
        endcase
    end

endmodule

