parameter hpixels = 800; 
 parameter vlines = 521; 
 parameter hpulse = 96; 
 parameter vpulse = 2; 
 parameter hbp = 144; 
 parameter hfp = 784; 
 parameter vbp = 31; 
 parameter vfp = 511; 
 reg [9:0] hc; 
 reg [9:0] vc; 
 assign x = hc - hbp; 
 assign y = vc - vbp; 
 always @(posedge dclk or posedge clr) 
 begin 
  if (clr == 1) 
  begin 
  hc <= 0; 
  vc <= 0; 
  end 
  else 
  begin 
  if (hc < hpixels - 1) 
  hc <= hc + 1; 
  else 
  begin 
  hc <= 0; 
  if (vc < vlines - 1) 
  vc <= vc + 1; 
  else 
  vc <= 0; 
  end 
  end 
 end 
 assign hsync = (hc < hpulse) ? 0:1; 
 assign vsync = (vc < vpulse) ? 0:1; 
 always @(*) 
 begin 
  if (vc >= vbp && vc < vfp) 
  begin 
  if (hc >= hbp && hc < (hbp+80)) 
  begin 
  red = 3'b111; 
  green = 3'b111; 
  blue = 2'b11; 
