module autovcoder_080226 (
    input  wire       clk100MHz,
    input  wire       rst,
    input  wire       button,
    input  wire [7:0] switches,
    output wire       we_dm,
    output wire [7:0] LEDSEL,
    output wire [7:0] LEDOUT
);

  reg  [31:0] reg_hex;
  wire        clk_sec;
  wire        clk_5KHz;
  wire        clk_pb;

  wire [ 7:0] digit0;
  wire [ 7:0] digit1;
  wire [ 7:0] digit2;
  wire [ 7:0] digit3;
  wire [ 7:0] digit4;
  wire [ 7:0] digit5;
  wire [ 7:0] digit6;
  wire [ 7:0] digit7;

  wire [31:0] pc_current;
  wire [31:0] instr;
  wire [31:0] alu_out;
  wire [31:0] wd_dm;
  wire [31:0] rd_dm;
  wire [31:0] dispData;

  clk_gen clk_gen (
      .clk100MHz(clk100MHz),
      .rst      (rst),
      .clk_4sec (clk_sec),
      .clk_5KHz (clk_5KHz)
  );

  button_debouncer bd (
      .clk             (clk_5KHz),
      .button          (button),
      .debounced_button(clk_pb)
  );

  mips_top mips_top (
      .clk       (clk_pb),
      .rst       (rst),
      .ra3       (switches[4:0]),
      .we_dm     (we_dm),
      .pc_current(pc_current),
      .instr     (instr),
      .alu_out   (alu_out),
      .wd_dm     (wd_dm),
      .rd_dm     (rd_dm),
      .rd3       (dispData)
  );

  /*
    switches[4:0] are used as the 3rd read address (ra3) of the RF,
    dispData is the register contents from the RF's 3rd read port (rd3).
    */

  hex_to_7seg hex7 (
      .HEX(reg_hex[31:28]),
      .s  (digit7)
  );

  hex_to_7seg hex6 (
      .HEX(reg_hex[27:24]),
      .s  (digit6)
  );

  hex_to_7seg hex5 (
      .HEX(reg_hex[23:20]),
      .s  (digit5)
  );

  hex_to_7seg hex4 (
      .HEX(reg_hex[19:16]),
      .s  (digit4)
  );

  hex_to_7seg hex3 (
      .HEX(reg_hex[15:12]),
      .s  (digit3)
  );

  hex_to_7seg hex2 (
      .HEX(reg_hex[11:8]),
      .s  (digit2)
  );

  hex_to_7seg hex1 (
      .HEX(reg_hex[7:4]),
      .s  (digit1)
  );

  hex_to_7seg hex0 (
      .HEX(reg_hex[3:0]),
      .s  (digit0)
  );

  led_mux led_mux (
      .clk   (clk_5KHz),
      .rst   (rst),
      .LED7  (digit7),
      .LED6  (digit6),
      .LED5  (digit5),
      .LED4  (digit4),
      .LED3  (digit3),
      .LED2  (digit2),
      .LED1  (digit1),
      .LED0  (digit0),
      .LEDSEL(LEDSEL),
      .LEDOUT(LEDOUT)
  );

  /*
    switches [7:5] = 000: Display word of register selected by switches[4:0]

    switches [7:5] = 001: Display word of instr

    switches [7:5] = 010: Display word of 'alu_out'

    switches [7:5] = 011: Display word of 'wd_dm'

    switches [7:5] = 1XX : Display word of 'pc_current'
    */
  always @(posedge clk100MHz) begin
    casez ({
      switches[7:5]
    })
      3'b000:  reg_hex = dispData[31:0];
      3'b001:  reg_hex = instr[31:0];
      3'b010:  reg_hex = alu_out[31:0];
      3'b011:  reg_hex = wd_dm[31:0];
      3'b1??:  reg_hex = pc_current[31:0];
      default: reg_hex = pc_current[31:0];
    endcase
  end

endmodule

