                    c1_4 <= c2_5;
                    c2_5 <= c3_6;
                    c3_6 <= c4_7;
                    c4_7 <= c5_8;
                    c5_8 <= c6_9;
                    c6_9 <= c7_10;
                    c7_10 <= c8_11;
                    c8_11 <= c9_12;
                    c9_12 <= c10_13;
                    c10_13 <= c11_14;
                    c11_14 <= 8'd126;
                end
            end
        endcase
    end
end

always @(posedge clk) begin
    if (loop_loop_waiting & seq2_18_startable & (~seq2_18_started)) begin
        outbyte_reg <= c0_3;
        outbyte_ready <= 1;
        seq2_18 <= 1;
    end else begin
        outbyte_ready <= 0;
        seq2_18 <= 0;
    end
end

assign outchan = outbyte_reg;
assign result = loop_loop_result_1;
assign result_ready = (loop_loop_result_1_ready & (~start));

endmodule

