    default: data_filtered_ready <= 1'b0;
  endcase
end

always @(*) begin
  case (count)
    4'h3: i_q_ready <= 1'b1;
    4'h4: i_q_ready <= 1'b1;
    4'hA: i_q_ready <= 1'b1;
    4'hB: i_q_ready <= 1'b1;
    default: i_q_ready <= 1'b0;
  endcase
end

always @(*) begin
  case (count)
    4'h5: i_q_filtered_ready <= 1'b1;
    4'h6: i_q_filtered_ready <= 1'b1;
    4'hC: i_q_filtered_ready <= 1'b1;
    4'hD: i_q_filtered_ready <= 1'b1;
