            end
        end
        OUT_S: begin           
            if(crc_cnt == 2'b00) begin
                gmii_tx_en <= 1'b1;
                gmii_txd   <= lastcrc[15:8];
                ctrl_state <= OUT_S;  
                crc_cnt <= crc_cnt + 1'b1;
            end
            else if(crc_cnt == 2'b01) begin
                gmii_tx_en <= 1'b1;
                gmii_txd   <= lastcrc[23:16];
                crc_cnt <= crc_cnt + 1'b1;
                ctrl_state <= OUT_S; 
            end
            else if(crc_cnt == 2'b10) begin
                gmii_tx_en <= 1'b1;
                gmii_txd   <= lastcrc[31:24];
                crc_cnt <= crc_cnt + 1'b1;
                ctrl_state <= OUT_S; 
            end
            else begin
                gmii_tx_en <= 1'b0;
                gmii_tx_er <= 1'b0;
                gmii_txd <= 8'b0;
                crc_cnt <= 2'b0;
                next_crc <= 32'hffffffff;
                ctrl_state <= IDLE_S; 
            end
        end
        default: ctrl_state <= IDLE_S;
        endcase 
    end
end

endmodule

