            i2 = 0; i_underflow <= 1;
        end else begin
            i2 = i1; i_underflow <= 0;
        end
        if (i2 > 88) begin
            i3 = 88; i_overflow <= 1;
        end else begin
            i3 = i2; i_overflow <= 0;
        end
        if (sign)
            sdelta = delta4 + 8;
        else
            sdelta = delta4;
    end

    assign y_out = sdelta;
    assign p_out = valpred;
    assign i_out = index;
    assign sz_out = step;
    assign s_out = sign;
    assign err = va_d - valpred;

endmodule

