module rtlpp_01833 (
    input clk,
    input reset,
    input signed [15:0] x_in,
    output [3:0] y_out,
    output signed [15:0] p_out,
    output reg p_underflow, p_overflow,
    output signed [7:0] i_out,
    output reg i_underflow, i_overflow,
    output signed [15:0] err,
    output [14:0] sz_out,
    output s_out
);

    reg signed [15:0] va, va_d;
    reg sign;
    reg [3:0] sdelta;
    reg [14:0] step;
    reg signed [15:0] sstep;
    reg signed [15:0] valpred;
    reg signed [7:0] index;
    reg signed [16:0] diff0, diff1, diff2, diff3;
    reg signed [16:0] p1, p2, p3;
    reg signed [7:0] i1, i2, i3;
    reg [3:0] delta2, delta3, delta4;
    reg [14:0] tStep;
    reg signed [15:0] vpdiff2, vpdiff3, vpdiff4;

    wire [14:0] t [0:88];
    wire signed [4:0] indexTable[0:15];

    assign indexTable[0] = -1; assign indexTable[1] = -1;
    assign indexTable[2] = -1; assign indexTable[3] = -1;
    assign indexTable[4] = 2; assign indexTable[5] = 4;
    assign indexTable[6] = 6; assign indexTable[7] = 8;
    assign indexTable[8] = -1; assign indexTable[9] = -1;
    assign indexTable[10] = -1; assign indexTable[11] = -1;
    assign indexTable[12] = 2; assign indexTable[13] = 4;
    assign indexTable[14] = 6; assign indexTable[15] = 8;

    assign t[0] = 7; assign t[1] = 8; assign t[2] = 9;
    assign t[3] = 10; assign t[4] = 11; assign t[5] = 12;
    assign t[6] = 13; assign t[7] = 14; assign t[8] = 16;
    assign t[9] = 17; assign t[10] = 19; assign t[11] = 21;
    assign t[12] = 23; assign t[13] = 25; assign t[14] = 28;
    assign t[15] = 31; assign t[16] = 34; assign t[17] = 37;
    assign t[18] = 41; assign t[19] = 45; assign t[20] = 50;
    assign t[21] = 55; assign t[22] = 60; assign t[23] = 66;
    assign t[24] = 73; assign t[25] = 80; assign t[26] = 88;
    assign t[27] = 97; assign t[28] = 107; assign t[29] = 118;
    assign t[30] = 130; assign t[31] = 143; assign t[32] = 157;
    assign t[33] = 173; assign t[34] = 190; assign t[35] = 209;
    assign t[36] = 230; assign t[37] = 253; assign t[38] = 279;
    assign t[39] = 307; assign t[40] = 337; assign t[41] = 371;
    assign t[42] = 408; assign t[43] = 449; assign t[44] = 494;
    assign t[45] = 544; assign t[46] = 598; assign t[47] = 658;
    assign t[48] = 724; assign t[49] = 796; assign t[50] = 876;
    assign t[51] = 963; assign t[52] = 1060; assign t[53] = 1166;
    assign t[54] = 1282; assign t[55] = 1411; assign t[56] = 1552;
    assign t[57] = 1707; assign t[58] = 1878; assign t[59] = 2066;
    assign t[60] = 2272; assign t[61] = 2499; assign t[62] = 2749;
    assign t[63] = 3024; assign t[64] = 3327; assign t[65] = 3660;
    assign t[66] = 4026; assign t[67] = 4428; assign t[68] = 4871;
    assign t[69] = 5358; assign t[70] = 5894; assign t[71] = 6484;
    assign t[72] = 7132; assign t[73] = 7845; assign t[74] = 8630;
    assign t[75] = 9493; assign t[76] = 10442; assign t[77] = 11487;
    assign t[78] = 12635; assign t[79] = 13899;
    assign t[80] = 15289; assign t[81] = 16818;
    assign t[82] = 18500; assign t[83] = 20350;
    assign t[84] = 22385; assign t[85] = 24623;
    assign t[86] = 27086; assign t[87] = 29794;
    assign t[88] = 32767;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            va <= 0;
            va_d <= 0;
            step <= 0;
            index <= 0;
            valpred <= 0;
        end else begin
            va_d <= va;
            va <= x_in;
            step <= t[i3];
            index <= i3;
            valpred <= p3;
        end
    end

    always @(va, va_d, step, index, valpred) begin
        diff0 = va - valpred;
        if (diff0 < 0) begin
            sign = 1;
            diff1 = -diff0;
        end else begin
            sign = 0;
            diff1 = diff0;
        end

        if (diff1 >= step) begin
            delta2 = 4;
            diff2 = diff1 - step;
            vpdiff2 = step / 8 + step;
        end else begin
            delta2 = 0;
            diff2 = diff1;
            vpdiff2 = step / 8;
        end

        if (diff2 >= step / 2) begin
            delta3 = delta2 + 2;
            diff3 = diff2 - step / 2;
            vpdiff3 = vpdiff2 + step / 2;
        end else begin
            delta3 = delta2;
            diff3 = diff2;
            vpdiff3 = vpdiff2;
        end

        if (diff3 >= step / 4) begin
            delta4 = delta3 + 1;
            vpdiff4 = vpdiff3 + step / 4;
        end else begin
            delta4 = delta3;
            vpdiff4 = vpdiff3;
        end

        if (sign)
            p1 = valpred - vpdiff4;
        else
            p1 = valpred + vpdiff4;

        if (p1 > 32767) begin
            p2 = 32767; p_overflow <= 1;
        end else begin
            p2 = p1; p_overflow <= 0;
        end
        if (p2 < -32768) begin
            p3 = -32768; p_underflow <= 1;
        end else begin
            p3 = p2; p_underflow <= 0;
        end

        i1 = index + indexTable[delta4];
        if (i1 < 0) begin
            i2 = 0; i_underflow <= 1;
        end else begin
            i2 = i1; i_underflow <= 0;
        end
        if (i2 > 88) begin
            i3 = 88; i_overflow <= 1;
        end else begin
            i3 = i2; i_overflow <= 0;
        end
        if (sign)
            sdelta = delta4 + 8;
        else
            sdelta = delta4;
    end

    assign y_out = sdelta;
    assign p_out = valpred;
    assign i_out = index;
    assign sz_out = step;
    assign s_out = sign;
    assign err = va_d - valpred;

endmodule

files.autovcoder_096753.v:
module autovcoder_096753 (
    output clk,
    output rst,

    output [3:0] srcReg1,
    output [3:0] srcReg2,
    output [3:0] nextDestReg,

    output [3:0] destReg,
    output [15:0] destVal,
    output storeNow,
    input storeDone,

    input [15:0] srcRegVal1,
    input [15:0] srcRegVal2,
    input inuse1,
    input inuse2
);

  reg clk, rst, storeNow;
  reg [3:0] srcReg1, srcReg2, nextDestReg, destReg;
  reg [15:0] destVal;

  RegisterFile R (
      clk,
      rst,
      srcReg1,
      srcReg2,
      nextDestReg,
      destReg,
      destVal,
      storeNow,
      storeDone,
      srcRegVal1,
      srcRegVal2,
      inuse1,
      inuse2
  );

  always begin
    #5 clk = ~clk;
  end

  initial begin
    $dumpfile("regfile.vcd");
    $dumpvars(0, regfile_TestBench);

    $monitor($time,, {"clk: %b,rst: %b, srcReg1: %x, srcReg2: %x, nextDestReg: %x,",
                      " destReg: %x, destVal: %d, storeNow: %b, storeDone: %b,",
                      " srcRegVal1: %x, srcRegVal2: %x, inuse1: %b, inuse2: %b", "\nRegs:",
                      " 0:%x %b, 1:%x %b, 2:%x %b, 3:%x %b, 4:%x %b,",
                      " 5:%x %b, 6:%x %b, 7:%x %b, 8:%x %b,",
                      " 9:%x %b, 10:%x %b, 11:%x %b, 12:%x %b,", " 13:%x %b, 14:%x %b, 15:%x %b"},
             clk, rst, srcReg1, srcReg2, nextDestReg, destReg, destVal, storeNow, storeDone,
             srcRegVal1, srcRegVal2, inuse1, inuse2, R.r[0], R.inuse[0], R.r[1], R.inuse[1],
             R.r[2], R.inuse[2], R.r[3], R.inuse[3], R.r[4], R.inuse[4], R.r[5], R.inuse[5],
             R.r[6], R.inuse[6], R.r[7], R.inuse[7], R.r[8], R.inuse[8], R.r[9], R.inuse[9],
             R.r[10], R.inuse[10], R.r[11], R.inuse[11], R.r[12], R.inuse[12], R.r[13],
             R.inuse[13], R.r[14], R.inuse[14], R.r[15], R.inuse[15]);

    // Begin testcases
    #0 srcReg1 = 0;
    srcReg2 = 1;
    nextDestReg = 2;
    destReg = 3;
    destVal = 256;
    storeNow = 1;

    #10 srcReg1 = 2;

    #10 srcReg2 = 3;

    #10 nextDestReg = 4;

    #10 destReg = 5;

    #10 destVal = 128;

    #10 storeNow = 0;

    #10 rst = 1;

    #10 srcReg1 = 0;
    srcReg2 = 1;
    nextDestReg = 2;
    destReg = 3;
    destVal = 256;
    storeNow = 1;

    #20 $finish;
  end


  /*
		System Verilog Assertions
		-------------------------

		Added by Rahul Kejriwal, CS14B023		
	*/


  /*
		Assert lookup of registers
	*/
  property P1;
    @(posedge clk)
			srcRegVal1 == R.r[srcReg1] and 
			srcRegVal2 == R.r[srcReg2] and 
			inuse1     == R.inuse[srcReg1] and
			inuse2 	   == R.inuse[srcReg2];
  endproperty

  RegLookup :
  assert property (P1)
  else $display("Failure at RegLookup");

  /*
		Assert inuse set and reset 
	*/
  property P2;
    reg [7:0] next_dest
    ;
    reg [7:0] dest;

    @(posedge clk) (1,
    next_dest = nextDestReg
    ,
    dest = destReg
    ) ##1 ((dest == next_dest or R.inuse[dest] == 0) and(R.inuse[next_dest] == 1));
  endproperty

  InuseSetReset :
  assert property (P2)
  else $display("Failure at InuseSetReset");

  /*
		Assert writing of register
	*/
  property P4;
    @(posedge clk) $rose(
        storeDone
    ) |-> R.r[destReg] == destVal;
  endproperty

  WriteAtSignal :
  assert property (P4)
  else $display("Failure at WriteAtSignal");

  /*
		Assert reset properties
	*/
  property P5;
    @(posedge clk) $rose(
        rst
    ) |-> srcRegVal1 == 16'b0 and srcRegVal2 == 16'b0 and inuse1 == 0 and inuse2 ==
        0 and storeDone == 0;
  endproperty

  ResetSignals :
  assert property (P5)
  else $display("Failure at ResetSignals");

  /*
		Assert Reset of registers and inuse bits 
	*/
  property ResetProp(i);
    @(posedge clk) $rose(
        rst
    ) |-> R.r[i] == 0 and R.inuse[i] == 0;
  endproperty

  generate
    for (genvar i = 0; i < 16; i++)
    assert property (ResetProp(i))
    else $display("Failure at ResetProp(%d)", i);
  endgenerate

  /*
    	Assert eventual storeDone after storeNow
    */
  property P7;
    @(posedge storeNow) ##[1:$] $rose(
        storeDone
    );
  endproperty

  EventualStoreDone :
  assert property (P7)
  else $display("Failure at EventualStoreDone");

endmodule

files.conformal_rtl_autovcoder_096753.do:
// Conformal LEC RTL vs RTL: combinational equivalence (no netlist, no technology library).
// Golden and revised in ./rtl/golden.v, ./rtl/revised.v.
// Uses -SystemVerilog for SV support (logic, always_comb, int, $bits, etc); backward compatible with Verilog.
// NOTE: Conformal uses // for comments. Do NOT use # (Conformal treats # as a command and aborts).

set undefined cell black_box
read design ./rtl/golden.v -SystemVerilog -Golden
read design ./rtl/revised.v -SystemVerilog -Revised

// Switch to LEC mode and compare
set system mode lec
add compared points -all
compare
exit -force

