    always @(posedge clk or posedge reset)
    begin
      if (reset)
      begin
        fifo_head <= 0;
        fifo_tail <= 0;
        fifo_count <= 0;
      end
      else if (sw_reset)
      begin
        fifo_head <= 0;
        fifo_tail <= 0;
        fifo_count <= 0;
      end
      else
