module autovcoder_004174 (
    clk,
    kld,
    out,
    out_n
);
  input clk;
  input kld;
  output [31:0] out;
  output [31:0] out_n;

  reg  [31:0] out;
  reg  [31:0] out_n;
  reg  [ 3:0] rcnt;
  wire [ 3:0] rcnt_next;

  assign out_n = ~out;

  always @(posedge clk)
    if (kld) begin
      out <= #1 32'h01_00_00_00;
      //out_n <= #1 !out;
    end else begin
      out <= #1 frcon(rcnt_next);
      //out_n <= #1 !out;
    end

  assign rcnt_next = rcnt + 4'h1;
  always @(posedge clk)
    if (kld) rcnt <= #1 4'h0;
    else rcnt <= #1 rcnt_next;

  function [31:0] frcon;
    input [3:0] i;
    case (i)  // synopsys parallel_case
      4'h0: frcon = 32'h01_00_00_00;
      4'h1: frcon = 32'h02_00_00_00;
      4'h2: frcon = 32'h04_00_00_00;
      4'h3: frcon = 32'h08_00_00_00;
      4'h4: frcon = 32'h10_00_00_00;
      4'h5: frcon = 32'h20_00_00_00;
      4'h6: frcon = 32'h40_00_00_00;
      4'h7: frcon = 32'h80_00_00_00;
      4'h8: frcon = 32'h1b_00_00_00;
      4'h9: frcon = 32'h36_00_00_00;
      default: frcon = 32'h00_00_00_00;
    endcase
  endfunction

endmodule

files.autovcoder_100415.v:
module autovcoder_100415 #(
    parameter ADDR_BITS   = 4,
    parameter DATA_BITS   = 8,
    parameter RAM_LATENCY = 2,
    // parameter WE_SIZE     = 1,

    parameter RESET      = 0,
    parameter RESET_HIGH = 0
) (
    input                  clk,
    input  [ADDR_BITS-1:0] addr_i,
    output [DATA_BITS-1:0] rd_o,
    input  [DATA_BITS-1:0] wd_i,
    input                  cs_i,
    input  [DATA_BITS-1:0] we_i
);
  reg [DATA_BITS-1:0]    rdata_reg;
  reg [DATA_BITS-1:0]    mem[(1'b1<<ADDR_BITS)-1:0];

  genvar i;
  generate
    if ((RESET != 0) && (RESET_HIGH != 0)) begin : g_reset_high
      for (i = 0; i < (1'b1 << ADDR_BITS); i = i + 1) begin : g_each_address
        initial mem[i] = {DATA_BITS{1'b1}};
      end
    end else if (RESET != 0) begin : g_reset_low
      for (i = 0; i < (1'b1 << ADDR_BITS); i = i + 1) begin : g_each_address
        initial mem[i] = {DATA_BITS{1'b0}};
      end
    end
  endgenerate

  wire read_cycle = cs_i & (~|we_i);
  wire write_cycle = cs_i & (|we_i);

  wire [DATA_BITS-1:0] real_we;

  genvar j;

  generate
    for (j = 0; j < DATA_BITS; j = j + 1) begin : g_we
      assign real_we[j] = cs_i ? we_i[j] : 1'b0;
    end
  endgenerate


  wire [DATA_BITS-1:0] nxt_data = (~real_we & mem[addr_i]) | (real_we & wd_i);






  always @(posedge clk) if (write_cycle) mem[addr_i] <= nxt_data;






  wire [DATA_BITS-1:0] rdata_nxt = (read_cycle ? mem[addr_i] : {DATA_BITS{1'bX}});

  always @(posedge clk) if (read_cycle) rdata_reg <= rdata_nxt;


  assign rd_o = rdata_reg;

endmodule

files.autovcoder_073055.v:
module autovcoder_073055 (
    clk,
    reset_,
    led
);

  input clk;
  input reset_;
  output [7:0] led;

  // Goal is to change LED pattern roughly every 250ms. The Papilio Pro
  // clock runs at 32 MHz (32.25 ns period). If we increment a 21 bit counter
  // on each clock cycle, it will roll over approximately each quarter second.
  // (Arithmetic left to the interested student.)
  reg [20:0] count;

  // Board has eight LEDs; this vector represents the state of each LED. A one
  // in the corresponding bit turns the LED on; a zero turns it off.
  reg [ 7:0] led;

  // A single bit indication of whether the LED animation is moving right
  // to left. (Once the active LED is in the left-most position, we clear this
  // value to signal we should start shifting right.)
  reg        left_shift;

  // Change the LED pattern each time our counter rolls over. The shift signal
  // will go high (1'b1) only for the single clock cycle where the counter is
  // maxed out. This is combinitorial logic; the value is continuously updated.
  assign shift = count == 21'h1FFFFF;

  // Increment the counter at each clock tick; set counter to 0 on reset.
  always @(posedge clk or negedge reset_)
    if (!reset_) count <= 21'h0;
    else count <= count + 1;

  // Shift the state of the LEDs each time the 'shift' signal is high (should
  // be the case only one clock cycle per ~250ms). LED state has one bit set,
  // the remaining seven cleared.
  always @(posedge clk or negedge reset_)
    if (!reset_) led[7:0] <= 8'b1000_0000;
    else if (shift && left_shift)  // Move 'on' LED left one position
      led[7:0] <= led[7:0] << 1;
    else if (shift)  // Move right
      led[7:0] <= led[7:0] >> 1;

  // Track whether we're moving left or right. When the 'on' LED reaches the
  // left-most position, clear this value. When it reaches the right-most
  // position, set it.
  always @(posedge clk or negedge reset_)
    if (!reset_) left_shift <= 1'b0;
    else if (led[7:0] == 8'b1000_0000) left_shift <= 1'b0;
    else if (led[7:0] == 8'b0000_0001) left_shift <= 1'b1;

endmodule

