module autovcoder_096201 (
    input rst,
    input clk,

    input  [68:0] rcn_in,
    output [68:0] rcn_out,

    input cs,
    input [1:0] seq,
    output busy,
    input wr,
    input [3:0] mask,
    input [23:0] addr,
    input [31:0] wdata,

    output rdone,
    output wdone,
    output [1:0] rsp_seq,
    output [3:0] rsp_mask,
    output [23:0] rsp_addr,
    output [31:0] rsp_data
);
  parameter MASTER_ID = 0;

  reg [68:0] rin;
  reg [68:0] rout;

  assign rcn_out = rout;

  wire [5:0] my_id = MASTER_ID;

  wire my_resp = rin[68] && !rin[67] && (rin[65:60] == my_id);

  wire req_valid;
  wire [68:0] req;

  always @(posedge clk or posedge rst)
    if (rst) begin
      rin  <= 69'd0;
      rout <= 69'd0;
    end else begin
      rin  <= rcn_in;
      rout <= (req_valid) ? req : (my_resp) ? 69'd0 : rin;
    end

  assign busy = rin[68] && !my_resp;
  assign req_valid = cs && !(rin[68] && !my_resp);
  assign req = {1'b1, 1'b1, wr, my_id, mask, addr[23:2], seq, wdata};

  assign rdone = my_resp && !rin[66];
  assign wdone = my_resp && rin[66];
  assign rsp_seq = rin[33:32];
  assign rsp_mask = rin[59:56];
  assign rsp_addr = {rin[55:34], 2'd0};
  assign rsp_data = rin[31:0];

endmodule

files.autovcoder_145663.v:
module autovcoder_145663(
    input wire clk,
    input wire reset,
    input wire valid,
    input wire [31:0] x1,
    input wire [31:0] y1,
    input wire [31:0] x2,
    input wire [31:0] y2,
    output reg [31:0] x3,
    output reg [31:0] y3,
    output reg done
);
    reg [31:0] lambda; // slope
    reg [31:0] x_temp;
    reg [31:0] y_temp;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            x3 <= 0;
            y3 <= 0;
            done <= 0;
        end else if (valid) begin
            // Check for the point at infinity
            if (x1 == 32'hFFFFFFFF && y1 == 32'hFFFFFFFF) begin
                x3 <= x2;
                y3 <= y2;
            end else if (x2 == 32'hFFFFFFFF && y2 == 32'hFFFFFFFF) begin
                x3 <= x1;
                y3 <= y1;
            end else begin
                // Calculate the slope (lambda)
                if (x1 == x2) begin
                    lambda <= 32'hFFFFFFFF; // Handle vertical line case
                end else begin
                    lambda <= (y2 - y1) / (x2 - x1); // Simplified slope calculation
                end
                // Calculate the resulting point (x3, y3)
                x_temp <= (lambda * (x2 - x1)) - x1 - x2;
                y_temp <= (lambda * (x_temp - x1)) - y1;
                x3 <= x_temp;
                y3 <= y_temp;
            end
            done <= 1;
        end
    end
endmodule

