module origen_027682(
    input clk,
    input rst_n,
    input [3:0] minute1, minute0, second1, second0,
    output reg alarm_radio
);

    parameter T1MS = 50000;
    parameter T500US = 25000;

    reg [15:0] C1, C2;
    reg F500HZ, F1KHZ;

    // Clock division
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            C1 <= 16'd0;
            C2 <= 16'd0;
            F500HZ <= 1'b0;
            F1KHZ <= 1'b0;
        end else begin
            if (C1 == T1MS - 1) begin
                C1 <= 16'd0;
                F500HZ <= ~F500HZ;
            end else begin
                C1 <= C1 + 1'b1;
            end

            if (C2 == T500US - 1) begin
                C2 <= 16'd0;
                F1KHZ <= ~F1KHZ;
            end else begin
                C2 <= C2 + 1'b1;
            end
        end
    end

    // Alarm logic
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            alarm_radio <= 1'b0;
        end else begin
            if (minute1 == 4'd5 && minute0 == 4'd9 && second1 == 4'd5 && (second0 == 4'd6 || second0 == 4'd8)) begin
                alarm_radio <= F500HZ;
            end else if (minute1 == 4'd0 && minute0 == 4'd0 && second1 == 4'd0 && second0 == 4'd0) begin
                alarm_radio <= F1KHZ;
            end else begin
                alarm_radio <= 1'b0;
            end
        end
    end

endmodule

files.autovcoder_125842.v:
module autovcoder_125842(  
    input wire clk,  
    input wire reset,  
    input wire [7:0] address,  
    input wire mode, // 0 for FIFO, 1 for LRU  
    output reg [3:0] cache_line_replaced  
);  
    reg [7:0] cache[3:0]; // 4 lines of cache  
    reg [1:0] head; // head pointer for FIFO  
    reg [3:0] lru_counter[3:0]; // LRU counters  
    reg [1:0] lru_index; // Index for selecting LRU line  
    integer i;  

    always @(posedge clk or posedge reset) begin  
        if (reset) begin  
            // Reset cache and pointers  
            head <= 0;  
            for (i = 0; i < 4; i = i + 1) begin  
                cache[i] <= 8'b0;  
                lru_counter[i] <= 0;  
            end  
            cache_line_replaced <= 4'b0;  
        end else begin  
            if (mode == 0) begin // FIFO  
                cache_line_replaced <= head;  
                cache[head] <= address;  
                head <= (head + 1) % 4;  
            end else begin // LRU  
                // Update LRU counters  
                for (i = 0; i < 4; i = i + 1) begin  
                    if (cache[i] != address) begin  
                        lru_counter[i] <= lru_counter[i] + 1;  
                    end  
                end  
                // Find the LRU index  
                lru_index = 0;  
                for (i = 1; i < 4; i = i + 1) begin  
                    if (lru_counter[i] > lru_counter[lru_index]) begin  
                        lru_index = i;  
                    end  
                end  
                cache_line_replaced <= lru_index;  
                cache[lru_index] <= address;  
                lru_counter[lru_index] <= 0; // Reset counter for the recently used line  
            end  
        end  
    end  
endmodule

