                     S3 = 4'b0011,
                     S4 = 4'b0100,
                     S5 = 4'b0101,
                     S6 = 4'b0110;

    reg [3:0] state, next_state;

    // State register
    always @(posedge clk or negedge rst) begin
        if (!rst)
            state <= S0;
