    reset,
    inp00,
    inp01,
    inp10,
    inp11,
    inp20,
    inp21,
    inp30,
    inp31,
    sum_out
);

  input clk;
  input reset;
  input [3:0] inp00;
  input [3:0] inp01;
  input [3:0] inp10;
  input [3:0] inp11;
  input [3:0] inp20;
  input [3:0] inp21;
  input [3:0] inp30;
  input [3:0] inp31;
