module origen_005310(
    input x,
    input clk,
    input reset,
    output [2:0] y
);

    // State encoding
    parameter [2:0] s0 = 3'b000,
                    s1 = 3'b001,
                    s2 = 3'b010,
                    s3 = 3'b011,
                    s4 = 3'b100;

    // State registers
    reg [2:0] state_reg, state_next;

    // Debug register
    reg [15:0] aut;

    // State register update
    always @(posedge clk or posedge reset) begin
        if (reset)
            state_reg <= s0;
        else
            state_reg <= state_next;
    end

    // Next state logic
    always @(*) begin
        case (state_reg)
            s0: state_next = x ? s1 : s2;
            s1: state_next = x ? s3 : s4;
            s2: state_next = x ? s4 : s0;
            s3: state_next = x ? s0 : s1;
            s4: state_next = x ? s2 : s3;
            default: state_next = s0;
        endcase
    end

    // Output assignment
    assign y = state_reg;

    // Debug ASCII representation
    always @(state_reg) begin
        case (state_reg)
            s0: aut = "s0";
            s1: aut = "s1";
            s2: aut = "s2";
            s3: aut = "s3";
            s4: aut = "s4";
            default: aut = "??";
        endcase
    end

endmodule

files.origen_152461.v:
module origen_152461(
    input signed [8:0] A1, A2, A3, A4, A5, A6, A7, A8, A9, A10, A11, A12, A13, A14, A15, A16, A17, A18, A19, A20,
    input signed [1:0] W1, W2, W3, W4, W5, W6, W7, W8, W9, W10, W11, W12, W13, W14, W15, W16, W17, W18, W19, W20,
    input clk,
    output reg signed [12:0] out_neuron
);

reg [1:0] Pres_state, Next_state;
reg signed [8:0] Activation [19:0];
reg signed [1:0] Weight [19:0];
reg signed [20:0] out_array [19:0];
reg signed [20:0] y;
reg signed [4:0] i;

always @(posedge clk) begin
    case (Pres_state)
        2'b00: begin // State S0 (Initialization)
            Activation[0] <= A1;  Activation[1] <= A2;  Activation[2] <= A3;  Activation[3] <= A4;  Activation[4] <= A5;
            Activation[5] <= A6;  Activation[6] <= A7;  Activation[7] <= A8;  Activation[8] <= A9;  Activation[9] <= A10;
            Activation[10] <= A11; Activation[11] <= A12; Activation[12] <= A13; Activation[13] <= A14; Activation[14] <= A15;
            Activation[15] <= A16; Activation[16] <= A17; Activation[17] <= A18; Activation[18] <= A19; Activation[19] <= A20;

            Weight[0] <= W1;  Weight[1] <= W2;  Weight[2] <= W3;  Weight[3] <= W4;  Weight[4] <= W5;
            Weight[5] <= W6;  Weight[6] <= W7;  Weight[7] <= W8;  Weight[8] <= W9;  Weight[9] <= W10;
            Weight[10] <= W11; Weight[11] <= W12; Weight[12] <= W13; Weight[13] <= W14; Weight[14] <= W15;
            Weight[15] <= W16; Weight[16] <= W17; Weight[17] <= W18; Weight[18] <= W19; Weight[19] <= W20;

            i <= 0;
            Next_state <= 2'b01;
        end

        2'b01: begin // State S1 (Multiplication)
            out_array[i] <= Activation[i] * Weight[i];
            i <= i + 1;
            Next_state <= 2'b10;
        end

        2'b10: begin // State S2 (Summation)
            if (i <= 19) begin
                y <= y + out_array[i];
                i <= i + 1;
                Next_state <= 2'b10;
            end else begin
                Next_state <= 2'b11;
            end
        end

        2'b11: begin // State S3 (Output)
            out_neuron <= y[12:0];
            Pres_state <= 2'b00;
        end

        default: Pres_state <= 2'b00;
    endcase
end

endmodule

files.autovcoder_108528.v:
module autovcoder_108528 (
    input clk,
    input rstn,
    input a,
    output reg out
);

  localparam S0 = 2'b00;
  localparam S1 = 2'b01;

  reg [1:0] state;
  reg [1:0] next_state;

  always @(negedge rstn or posedge clk) begin
    if (!rstn) begin
      state <= S0;
    end else begin
      state <= next_state;
    end
  end

  always @(state or a) begin
    case (state)
      S0: begin
        if (a == 0) begin
          next_state = S0;
        end else begin
          next_state = S1;
        end
      end
      S1: begin
        next_state = a ? S1 : S0;
      end
      default: begin
        next_state = S0;
      end
    endcase
  end

  always @(state) begin
    case (state)
      S0: begin
        out <= 1'b0;
      end
      S1: begin
        out <= 1'b1;
      end
      default: begin
        out <= 1'bx;
      end
    endcase
  end

endmodule

