module origen_197422(
    input clk,
    input rst_n,
    input [31:0] aluout,
    input [31:0] rd,
    input [31:0] ram_rd,
    output reg [5:0] ra,
    output reg [5:0] wa,
    output reg [31:0] wd,
    output reg [31:0] td,
    output reg ram_we,
    output reg [5:0] ram_ra
);

reg [1:0] state;

always @(negedge clk) begin
    if (!rst_n) begin
        state <= 2'b11;
        ra <= 6'b0;
        wa <= 6'b0;
    end
    else begin
        case (state)
            2'b11: state <= 2'b00;
            2'b00: begin
                wd <= ram_rd;
                wa <= wa + 1;
                state <= 2'b01;
            end
            2'b01: begin
                wd <= ram_rd;
                td <= rd;
                ra <= ra + 1;
                wa <= wa + 1;
                state <= 2'b10;
            end
            2'b10: begin
                wd <= aluout;
                td <= rd;
                ram_we <= 1;
                ra <= ra + 1;
                wa <= wa + 1;
                ram_ra <= ram_ra + 1;
                state <= 2'b10;
            end
        endcase
    end
end

endmodule

files.origen_019625.v:
module origen_019625 (
    input [7:0] char,
    input clk,
    output reg out
);

    // State encoding
    parameter S0 = 2'b00;
    parameter S1 = 2'b01;
    parameter S2 = 2'b10;

    reg [1:0] state, next_state;
    reg isalphabet, isnumber;

    // Determine if input is alphabet or number
    always @(*) begin
        isalphabet = ((char >= 8'h41 && char <= 8'h5A) || (char >= 8'h61 && char <= 8'h7A)) ? 1'b1 : 1'b0;
        isnumber = (char >= 8'h30 && char <= 8'h39) ? 1'b1 : 1'b0;
    end

    // State transition logic
    always @(*) begin
        case(state)
            S0: next_state = isalphabet ? S1 : S0;
            S1: begin
                if (isalphabet)
                    next_state = S1;
                else if (isnumber)
                    next_state = S2;
                else
                    next_state = S0;
            end
            S2: begin
                if (isalphabet)
                    next_state = S1;
                else if (isnumber)
                    next_state = S2;
                else
                    next_state = S0;
            end
            default: next_state = S0;
        endcase
    end

    // State register
    always @(posedge clk) begin
        state <= next_state;
    end

    // Output logic
    always @(*) begin
        out = (state == S2) ? 1'b1 : 1'b0;
    end

endmodule

files.origen_183988.v:
module origen_183988 #(
    parameter DETECT_THRESH = 4,
    parameter PREAMBLE_LEN = 8,
    parameter PREAMBLE_VAL = 8'b10101010
) (
    input CLK,
    input RESET,
    input DATA_IN,
    input DATA_IN_VALID,
    output reg DETECT_OUT,
    output reg DETECT_OUT_VALID
);

    reg [PREAMBLE_LEN-1:0] Preamble_Shift_Reg;
    reg [PREAMBLE_LEN-1:0] Preamble_Xor_Reg;
    reg [PREAMBLE_LEN-1:0] Sum_Val_Array [PREAMBLE_LEN-1:0];
    reg [PREAMBLE_LEN-1:0] Sum_Result;

    integer i;

    always @(posedge CLK or posedge RESET) begin
        if (RESET) begin
            Preamble_Shift_Reg <= 0;
            Preamble_Xor_Reg <= 0;
            Sum_Result <= 0;
            DETECT_OUT <= 0;
            DETECT_OUT_VALID <= 0;
        end
        else begin
            if (DATA_IN_VALID) begin
                Preamble_Shift_Reg <= {Preamble_Shift_Reg[PREAMBLE_LEN-2:0], DATA_IN};
                Preamble_Xor_Reg <= Preamble_Shift_Reg ^ PREAMBLE_VAL;

                Sum_Val_Array[0] <= Preamble_Xor_Reg;
                for (i = 1; i < PREAMBLE_LEN; i = i + 1) begin
                    Sum_Val_Array[i] <= Sum_Val_Array[i-1] >> 1;
                end

                Sum_Result <= 0;
                for (i = 0; i < PREAMBLE_LEN; i = i + 1) begin
                    Sum_Result <= Sum_Result + Sum_Val_Array[i];
                end

                if (Sum_Result > DETECT_THRESH) begin
                    DETECT_OUT <= 1;
                end
                else begin
                    DETECT_OUT <= 0;
                end

                DETECT_OUT_VALID <= ~DETECT_OUT_VALID;
            end
        end
    end

endmodule

files.origen_169373.v:
module origen_169373(
    input clk,
    input reset,
    output reg vga_clk,
    output reg hsync,
    output reg vsync,
    output [9:0] pixel_x,
    output [9:0] pixel_y,
    output video_on
);

    reg [9:0] h_count;
    reg [9:0] v_count;

    always @(posedge clk or posedge reset) begin
        if (reset) begin
            vga_clk <= 0;
        end else begin
            vga_clk <= ~vga_clk;
        end
    end

    always @(posedge vga_clk or posedge reset) begin
        if (reset) begin
            h_count <= 0;
            v_count <= 0;
        end else begin
            if (h_count == 799) begin
                h_count <= 0;
                if (v_count == 524)
                    v_count <= 0;
                else
                    v_count <= v_count + 1;
            end else begin
                h_count <= h_count + 1;
            end
        end
    end

    always @(*) begin
        if (h_count >= 96)
            hsync = 1'b0;
        else
            hsync = 1'b1;

        if (v_count >= 2)
            vsync = 1'b0;
        else
            vsync = 1'b1;
    end

    assign pixel_x = h_count - 143;
    assign pixel_y = v_count - 35;

    assign video_on = (h_count >= 143 && h_count <= 782 && v_count >= 35 && v_count <= 514);

endmodule

