module origen_087979 (
    input wire clock,
    input wire data,
    input wire preset,
    input wire reset,
    output reg Q
);

    always @(posedge clock or negedge preset or negedge reset) begin
        if (!preset)
            Q <= 1'b1;
        else if (!reset)
            Q <= 1'b0;
        else
            Q <= data;
