module origen_189993(
    input clk,
    input resetn,
    input inc_row,
    output reg [2:0] difficulty,
    output reg new_direction,
    output reg [6:0] new_y_position,
    output reg [7:0] new_x_position
);

    // Registers
    reg [4:0] r;

    // Constants
    parameter Y_ROW_0 = 7'd0;
    parameter Y_ROW_1 = 7'd10;
    parameter Y_ROW_2 = 7'd20;
    parameter Y_ROW_3 = 7'd30;
    parameter Y_ROW_4 = 7'd40;
    parameter Y_ROW_5 = 7'd50;
    parameter Y_ROW_6 = 7'd60;

    parameter LOW_DIFF = 3'd0;
    parameter MID_DIFF = 3'd1;
    parameter HIGH_DIFF = 3'd2;
    parameter MAX_DIFF = 3'd3;

    parameter X_INIT = 8'd0;
    parameter X_END = 8'd200;

    parameter GO_LEFT = 1'b0;
    parameter GO_RIGHT = 1'b1;

    always @(posedge clk or negedge resetn) begin
        if (!resetn) begin
            r <= 5'd0;
        end
        else if (inc_row) begin
            r <= r + 1'b1;
        end
    end

    always @(*) begin
        case (r)
            5'd0: begin
                new_y_position = Y_ROW_0;
                new_x_position = X_INIT;
                new_direction = GO_RIGHT;
                difficulty = LOW_DIFF;
            end
            5'd1: begin
                new_y_position = Y_ROW_1;
                new_x_position = X_END;
                new_direction = GO_LEFT;
                difficulty = LOW_DIFF;
            end
            5'd2: begin
                new_y_position = Y_ROW_2;
                new_x_position = X_INIT;
                new_direction = GO_RIGHT;
                difficulty = MID_DIFF;
            end
            5'd3: begin
                new_y_position = Y_ROW_3;
                new_x_position = X_END;
                new_direction = GO_LEFT;
                difficulty = MID_DIFF;
            end
            5'd4: begin
                new_y_position = Y_ROW_4;
                new_x_position = X_INIT;
                new_direction = GO_RIGHT;
                difficulty = HIGH_DIFF;
            end
            5'd5: begin
                new_y_position = Y_ROW_5;
                new_x_position = X_END;
                new_direction = GO_LEFT;
                difficulty = HIGH_DIFF;
            end
            5'd6: begin
                new_y_position = Y_ROW_6;
                new_x_position = X_INIT;
                new_direction = GO_RIGHT;
                difficulty = MAX_DIFF;
            end
            default: begin
                new_y_position = Y_ROW_0;
                new_x_position = X_INIT;
                new_direction = GO_RIGHT;
                difficulty = LOW_DIFF;
            end
        endcase
    end

endmodule

files.autovcoder_020707.v:
module autovcoder_020707 (
    clock,  // clock
    reset,  // Active high, syn reset
    req_0,  // Request 0
    req_1,  // Request 1
    gnt_0,  // Grant 0
    gnt_1
);
  //-------------Input Ports-----------------------------
  input clock, reset, req_0, req_1;
  //-------------Output Ports----------------------------
  output gnt_0, gnt_1;
  //-------------Input ports Data Type-------------------
  wire clock, reset, req_0, req_1;
  //-------------Output Ports Data Type------------------
  reg gnt_0, gnt_1;
  //-------------Internal Constants--------------------------
  parameter SIZE = 3;
  parameter IDLE = 3'b001, GNT0 = 3'b010, GNT1 = 3'b100;
  //-------------Internal Variables---------------------------
  reg  [SIZE-1:0] state;  // Seq part of the FSM
  wire [SIZE-1:0] next_state;  // combo part of FSM
  //----------Code startes Here------------------------
  assign next_state = fsm_function(state, req_0, req_1);
  //----------Function for Combo Logic-----------------
  function [SIZE-1:0] fsm_function;
    input [SIZE-1:0] state;
    input req_0;
    input req_1;
    case (state)
      IDLE:
      if (req_0 == 1'b1) begin
        fsm_function = GNT0;
      end else if (req_1 == 1'b1) begin
        fsm_function = GNT1;
      end else begin
        fsm_function = IDLE;
      end
      GNT0:
      if (req_0 == 1'b1) begin
        fsm_function = GNT0;
      end else begin
        fsm_function = IDLE;
      end
      GNT1:
      if (req_1 == 1'b1) begin
        fsm_function = GNT1;
      end else begin
        fsm_function = IDLE;
      end
      default: fsm_function = IDLE;
    endcase
  endfunction
  //----------Seq Logic-----------------------------
  always @(posedge clock) begin : FSM_SEQ
    if (reset == 1'b1) begin
      state <= #1 IDLE;
    end else begin
      state <= #1 next_state;
    end
  end
  //----------Output Logic-----------------------------
  always @(posedge clock) begin : OUTPUT_LOGIC
    if (reset == 1'b1) begin
      gnt_0 <= #1 1'b0;
      gnt_1 <= #1 1'b0;
    end else begin
      case (state)
        IDLE: begin
          gnt_0 <= #1 1'b0;
          gnt_1 <= #1 1'b0;
        end
        GNT0: begin
          gnt_0 <= #1 1'b1;
          gnt_1 <= #1 1'b0;
        end
        GNT1: begin
          gnt_0 <= #1 1'b0;
          gnt_1 <= #1 1'b1;
        end
        default: begin
          gnt_0 <= #1 1'b0;
          gnt_1 <= #1 1'b0;
        end
      endcase
    end
  end  // End Of Block OUTPUT_LOGIC

endmodule

