module origen_143282 (
    input wire clk,
    input wire rst,
    input wire [7:0] in_data,
    input wire in_valid,
    input wire [71:0] kernel,
    input wire kernel_valid,
    output reg [15:0] out_data,
    output reg out_valid
);

    // Parameters
    localparam IMG_SIZE = 8;
    localparam KERNEL_SIZE = 3;
    localparam RESULT_SIZE = IMG_SIZE - KERNEL_SIZE + 1;

    // Internal registers
    reg [7:0] image [0:IMG_SIZE-1][0:IMG_SIZE-1];
    reg [7:0] kernel_reg [0:KERNEL_SIZE-1][0:KERNEL_SIZE-1];
    reg [3:0] row_counter, col_counter;
    reg [3:0] kernel_row, kernel_col;
    reg [15:0] accumulator;
    reg [2:0] state;

    // State definitions
    localparam IDLE = 3'd0;
    localparam LOAD_IMAGE = 3'd1;
    localparam LOAD_KERNEL = 3'd2;
    localparam CONVOLVE = 3'd3;
    localparam OUTPUT = 3'd4;

    // State machine
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            row_counter <= 0;
            col_counter <= 0;
            kernel_row <= 0;
            kernel_col <= 0;
            out_valid <= 0;
        end else begin
            case (state)
                IDLE: begin
                    if (in_valid) state <= LOAD_IMAGE;
                    else if (kernel_valid) state <= LOAD_KERNEL;
                end
                LOAD_IMAGE: begin
                    if (row_counter == IMG_SIZE-1 && col_counter == IMG_SIZE-1) begin
                        state <= CONVOLVE;
                        row_counter <= 0;
                        col_counter <= 0;
                    end else if (col_counter == IMG_SIZE-1) begin
                        row_counter <= row_counter + 1;
                        col_counter <= 0;
                    end else begin
                        col_counter <= col_counter + 1;
                    end
                end
                LOAD_KERNEL: begin
                    if (kernel_row == KERNEL_SIZE-1 && kernel_col == KERNEL_SIZE-1) begin
                        state <= IDLE;
                        kernel_row <= 0;
                        kernel_col <= 0;
                    end else if (kernel_col == KERNEL_SIZE-1) begin
                        kernel_row <= kernel_row + 1;
                        kernel_col <= 0;
                    end else begin
                        kernel_col <= kernel_col + 1;
                    end
                end
                CONVOLVE: begin
                    if (row_counter == RESULT_SIZE-1 && col_counter == RESULT_SIZE-1) begin
                        state <= OUTPUT;
                        row_counter <= 0;
                        col_counter <= 0;
                    end else if (col_counter == RESULT_SIZE-1) begin
                        row_counter <= row_counter + 1;
                        col_counter <= 0;
                    end else begin
                        col_counter <= col_counter + 1;
                    end
                end
                OUTPUT: begin
                    if (row_counter == RESULT_SIZE-1 && col_counter == RESULT_SIZE-1) begin
                        state <= IDLE;
                        out_valid <= 0;
                    end else if (col_counter == RESULT_SIZE-1) begin
                        row_counter <= row_counter + 1;
                        col_counter <= 0;
                    end else begin
                        col_counter <= col_counter + 1;
                    end
                end
            endcase
        end
    end

    // Input data loading
    always @(posedge clk) begin
        if (state == LOAD_IMAGE && in_valid) begin
            image[row_counter][col_counter] <= in_data;
        end
    end

    // Kernel loading
    always @(posedge clk) begin
        if (state == LOAD_KERNEL && kernel_valid) begin
            kernel_reg[kernel_row][kernel_col] <= kernel[8*(kernel_row * KERNEL_SIZE + kernel_col) +: 8];
        end
    end

    // Convolution computation
    integer i, j;
    always @(posedge clk) begin
        if (state == CONVOLVE) begin
            accumulator <= 0;
            for (i = 0; i < KERNEL_SIZE; i = i + 1) begin
                for (j = 0; j < KERNEL_SIZE; j = j + 1) begin
                    accumulator <= accumulator + image[row_counter+i][col_counter+j] * kernel_reg[i][j];
                end
            end
        end
    end

    // Output
    always @(posedge clk) begin
        if (state == OUTPUT) begin
            out_data <= accumulator;
            out_valid <= 1;
        end
    end

endmodule

