module origen_123918 (
    input wire clk,
    input wire rst,
    input wire [63:0] citya,
    input wire [63:0] cityb,
    input wire inp_valid,
    output reg out_valid,
    output reg [31:0] out
);

    // Internal signals
    reg [31:0] dx, dy;
    reg [63:0] dx_squared, dy_squared;
    reg [63:0] sum_squared;
    reg [23:0] sqrt_input;
    wire [15:0] sqrt_output;
    wire sqrt_valid;
    reg sqrt_start;

    // State machine
    localparam IDLE = 2'b00;
    localparam CALCULATE = 2'b01;
    localparam WAIT_SQRT = 2'b10;
    localparam OUTPUT = 2'b11;

    reg [1:0] state, next_state;

    // CORDIC square root module instantiation
    cordic_sqrt sqrt_module (
        .aclk(clk),
        .s_axis_cartesian_tvalid(sqrt_start),
        .s_axis_cartesian_tdata(sqrt_input),
        .m_axis_dout_tvalid(sqrt_valid),
        .m_axis_dout_tdata(sqrt_output)
    );

    // State machine and calculations
    always @(posedge clk or posedge rst) begin
        if (rst) begin
            state <= IDLE;
            out_valid <= 1'b0;
            out <= 32'd0;
            dx <= 32'd0;
            dy <= 32'd0;
            dx_squared <= 64'd0;
            dy_squared <= 64'd0;
            sum_squared <= 64'd0;
            sqrt_input <= 24'd0;
            sqrt_start <= 1'b0;
        end else begin
            state <= next_state;
            case (state)
                IDLE: begin
                    out_valid <= 1'b0;
                    if (inp_valid) begin
                        dx <= citya[31:0] - cityb[31:0];
                        dy <= citya[63:32] - cityb[63:32];
                    end
                end
                CALCULATE: begin
                    dx_squared <= dx * dx;
                    dy_squared <= dy * dy;
                    sum_squared <= dx_squared + dy_squared;
                    sqrt_input <= sum_squared[23:0];
                    sqrt_start <= 1'b1;
                end
                WAIT_SQRT: begin
                    sqrt_start <= 1'b0;
                    if (sqrt_valid) begin
                        out <= {16'd0, sqrt_output};
                    end
                end
                OUTPUT: begin
                    out_valid <= 1'b1;
                end
            endcase
        end
    end

    // Next state logic
    always @(*) begin
        case (state)
            IDLE:
                next_state = inp_valid ? CALCULATE : IDLE;
            CALCULATE:
                next_state = WAIT_SQRT;
            WAIT_SQRT:
                next_state = sqrt_valid ? OUTPUT : WAIT_SQRT;
            OUTPUT:
                next_state = IDLE;
            default:
                next_state = IDLE;
        endcase
    end

endmodule

